 23→
 24→//// Softmax Functions
 25→
 26→int32_t riscv_nn_softmax_f32(const float32_t * in_vec, uint32_t size, float32_t * out_vec)
 27→{
 28→#ifdef ENA_EMPTY_FUN
 29→    //empty body
 30→#else
 31→#if defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU) && !defined(ENA_ACE_RVV)
 32→    //--- const values for taylor_poly_f32 ---
 33→    // Exponent polynomial coefficients
 34→    const float32_t exp_coe0 = EXP_COE0;
 35→    const float32_t exp_coe1 = EXP_COE1;
 36→    const float32_t exp_coe2 = EXP_COE2;
 37→    const float32_t exp_coe3 = EXP_COE3;
 38→    const float32_t exp_coe4 = EXP_COE4;
 39→    const float32_t exp_coe5 = EXP_COE5;
 40→    const float32_t exp_coe6 = EXP_COE6;
 41→    const float32_t exp_coe7 = EXP_COE7;
 42→    //--- const values for exp_f32 ---
 43→    const float32_t ln2      = LN2;          // ln(2)
 44→    const float32_t inv_ln2  = INV_LN2;      // 1/ln(2)
 45→#endif
 46→
 47→#if defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU) && defined(ENA_ACE_RVV)
 48→    float32_t max, sum;
 49→    float32_t *in_vec2, *out_vec2;
 50→    long vl;
 51→    long size2 = size;
 52→    long ele_per_loop, ele_per_loop2;
 53→
 54→    //find the maximun
 55→    in_vec2 = (float32_t *)in_vec;
 56→    NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 57→    NDS_VEC_VLE32_V(NDS_VEC_V0, in_vec2);
 58→    in_vec2 += vl;
 59→    size2 -= vl;
 60→    while(size2 > 0)
 61→    {
 62→        NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 63→        NDS_VEC_VLE32_V(NDS_VEC_V8, in_vec2);
 64→        in_vec2 += vl;
 65→        size2 -= vl;
 66→        NDS_VEC_VFMAX_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);
 67→    }
 68→    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note teh avl here
 69→    NDS_VEC_VFREDMAX_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V0);
 70→    NDS_VEC_VFMV_F_S(max, NDS_VEC_V0);
 71→
 72→    //calculate the exp and sum
 73→    NDS_VEC_VSETVLI(ele_per_loop2, reg_x0, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 74→    ele_per_loop = ele_per_loop2 * 3;
 75→    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 76→    NDS_VEC_VAND_VI(NDS_VEC_V24, NDS_VEC_V24, 0);   //init sum
 77→    in_vec2 = (float32_t *)in_vec;
 78→    out_vec2 = out_vec;
 79→    size2 = size;
 80→    NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 81→    while(size2 >= ele_per_loop)
 82→    {
 83→        NDS_VEC_VLE32_V(NDS_VEC_V0, in_vec2);
 84→        in_vec2 += vl;
 85→        NDS_VEC_VLE32_V(NDS_VEC_V8, in_vec2);
 86→        in_vec2 += vl;
 87→        NDS_VEC_VLE32_V(NDS_VEC_V16, in_vec2);
 88→        in_vec2 += vl;
 89→        NDS_VEC_VFSUB_VF(NDS_VEC_V0, NDS_VEC_V0, max);
 90→        size2 -= ele_per_loop;
 91→        NDS_VEC_VFSUB_VF(NDS_VEC_V8, NDS_VEC_V8, max);
 92→        NDS_VEC_VFSUB_VF(NDS_VEC_V16, NDS_VEC_V16, max);
 93→
 94→        //--- exp_f32 begin ---
 95→        ace_exp(NDS_VEC_V0, NDS_VEC_V0);
 96→        ace_exp(NDS_VEC_V8, NDS_VEC_V8);
 97→        ace_exp(NDS_VEC_V16, NDS_VEC_V16);
 98→        //--- exp_f32 end ---
 99→
100→        NDS_VEC_VFADD_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V0);     //accumulate sum_f32
101→        NDS_VEC_VFADD_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V8);     //accumulate sum_f32
102→        NDS_VEC_VFADD_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V16);    //accumulate sum_f32
103→        NDS_VEC_VSE32_V(NDS_VEC_V0, out_vec2);
104→        out_vec2 += vl;
105→        NDS_VEC_VSE32_V(NDS_VEC_V8, out_vec2);
106→        out_vec2 += vl;
107→        NDS_VEC_VSE32_V(NDS_VEC_V16, out_vec2);
108→        out_vec2 += vl;
109→    }
110→    while(size2 > 0)
111→    {
112→        NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
113→        NDS_VEC_VLE32_V(NDS_VEC_V0, in_vec2);
114→        in_vec2 += vl;
115→        NDS_VEC_VFSUB_VF(NDS_VEC_V0, NDS_VEC_V0, max);
116→        size2 -= vl;
117→
118→        //--- exp_f32 begin ---
119→        ace_exp(NDS_VEC_V0, NDS_VEC_V0);
120→        //--- exp_f32 end ---
121→
122→        NDS_VEC_VFADD_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V0);     //accumulate sum_f32
123→        NDS_VEC_VSE32_V(NDS_VEC_V0, out_vec2);
124→        out_vec2 += vl;
125→    }
126→    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
127→    NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);   //for redsum
128→    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
129→    NDS_VEC_VFREDSUM_VS(NDS_VEC_V0, NDS_VEC_V24, NDS_VEC_V0);
130→#ifdef ENA_FAST_ALGO
131→    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
132→    NDS_VEC_VFRECE7_V(NDS_VEC_V0, NDS_VEC_V0);
133→#endif
134→    NDS_VEC_VFMV_F_S(sum, NDS_VEC_V0);
135→
136→    //divide the output by sum
137→    ele_per_loop = ele_per_loop2 << 1;
138→    size2 = size;
139→    NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
140→    while (size2 >= ele_per_loop)
141→    {
142→        float32_t* out_vec2 = (float32_t*)out_vec + vl;
143→        NDS_VEC_VLE32_V(NDS_VEC_V0, out_vec);
144→        NDS_VEC_VLE32_V(NDS_VEC_V8, out_vec2);
145→#ifdef ENA_FAST_ALGO
146→        NDS_VEC_VFMUL_VF(NDS_VEC_V0, NDS_VEC_V0, sum);
147→        NDS_VEC_VFMUL_VF(NDS_VEC_V8, NDS_VEC_V8, sum);
148→#else
149→        NDS_VEC_VFDIV_VF(NDS_VEC_V0, NDS_VEC_V0, sum);
150→        NDS_VEC_VFDIV_VF(NDS_VEC_V8, NDS_VEC_V8, sum);
151→#endif
152→        NDS_VEC_VSE32_V(NDS_VEC_V0, out_vec);
153→        out_vec += ele_per_loop;
154→        NDS_VEC_VSE32_V(NDS_VEC_V8, out_vec2);
155→        size2 -= ele_per_loop;
156→    }
157→    while(size2 > 0)
158→    {
159→        NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
160→        NDS_VEC_VLE32_V(NDS_VEC_V0, out_vec);
161→#ifdef ENA_FAST_ALGO
162→        NDS_VEC_VFMUL_VF(NDS_VEC_V0, NDS_VEC_V0, sum);
163→#else
164→        NDS_VEC_VFDIV_VF(NDS_VEC_V0, NDS_VEC_V0, sum);
165→#endif
166→        NDS_VEC_VSE32_V(NDS_VEC_V0, out_vec);
167→        out_vec += vl;
168→        size2 -= vl;
169→    }
170→#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU)
171→    float32_t max, sum;
172→    float32_t *in_vec2, *out_vec2;
173→    long vl;
174→    long size2 = size;
175→    long ele_per_loop;
176→    const float32_t exp_max = EXP_F32_MAX;
177→    const float32_t exp_min = EXP_F32_MIN;
178→
179→#ifdef ENA_VEC_INTRINSIC
180→    //find the maximun
181→    in_vec2 = (float32_t *)in_vec;
182→    vl = __riscv_vsetvl_e32m8(size2);
183→    vfloat32m8_t vMax = __riscv_vle32_v_f32m8(in_vec2, vl);
184→    in_vec2 += vl;
185→    size2 -= vl;
186→    while(size2 > 0)
187→    {
188→        vl =__riscv_vsetvl_e32m8(size2);
189→        vfloat32m8_t vTmp = __riscv_vle32_v_f32m8(in_vec2, vl);
190→        vMax = __riscv_vfmax(vMax, vTmp, vl);
191→        in_vec2 += vl;
192→        size2 -= vl;
193→    }
194→    vfloat32m1_t vMax_e0;       //the element at v[0]
195→    vMax_e0 = __riscv_vfmv_v_f_f32m1(__FLT16_MIN__, size);
196→    vMax_e0 = __riscv_vfredmax_tu(vMax_e0, vMax, vMax_e0, size);
197→    max = __riscv_vfmv_f(vMax_e0);
198→
199→    //calculate the exp and sum
200→    vfloat32m4_t vSum = __riscv_vfmv_v_f_f32m4(0.f, size);
201→    vfloat32m1_t vOut_e0 = __riscv_vfmv_v_f_f32m1(0.f, size);       //the element at v[0]
202→    out_vec2 = out_vec;
203→    size2 = size;
204→    while(size2 > 0)
205→    {
206→        vfloat32m4_t vIn_f32;
207→        vfloat32m4_t vA, vB, vC, vD, vX2, vX4, vPoly_f32;
208→        vint32m4_t vPoly_i32;
209→
210→        vl = __riscv_vsetvl_e32m4(size2);
211→        vIn_f32 = __riscv_vle32_v_f32m4(in_vec, vl);
212→        vIn_f32 = __riscv_vfsub(vIn_f32, max, vl);
213→        vIn_f32 = __riscv_vfmax(vIn_f32, exp_min, vl);
214→        vIn_f32 = __riscv_vfmin(vIn_f32, exp_max, vl);
215→
216→        //--- exp_f32 begin ---
217→        // Perform range reduction [-log(2),log(2)]
218→        vfloat32m4_t vm = __riscv_vfmul(vIn_f32, inv_ln2, vl);          //x * inv_ln2;
219→        vint32m4_t vm_int = __riscv_vfcvt_rtz_x(vm, vl);                //m (integer type)
220→        vm = __riscv_vfcvt_f(vm_int, vl);                               //m (float type)
221→        vm = __riscv_vfnmsub_tu(vm, ln2, vIn_f32, vl);                  //val
222→
223→        //--- taylor_poly_f32 begin ---
224→        vA = __riscv_vfmv_v_f_f32m4(exp_coe0, vl);                      //A = exp_coe0
225→        vA = __riscv_vfmacc_tu(vA, exp_coe4, vm, vl);                   //A = exp_coe0 + x * exp_coe4
226→        vB = __riscv_vfmv_v_f_f32m4(exp_coe2, vl);                      //B = exp_coe2
227→        vB = __riscv_vfmacc_tu(vB, exp_coe6, vm, vl);                   //B = exp_coe2 + x * exp_coe6
228→        vC = __riscv_vfmv_v_f_f32m4(exp_coe1, vl);                      //C = exp_coe1
229→        vC = __riscv_vfmacc_tu(vC, exp_coe5, vm, vl);                   //C = exp_coe1 + x * exp_coe5
230→        vD = __riscv_vfmv_v_f_f32m4(exp_coe3, vl);                      //D = exp_coe3
231→        vD = __riscv_vfmacc_tu(vD, exp_coe7, vm, vl);                   //D = exp_coe3 + x * exp_coe7
232→        vX2 = __riscv_vfmul(vm, vm, vl);                                //x2
233→        vm_int = __riscv_vsll(vm_int, 23, vl);                          //m2
234→        vX4 = __riscv_vfmul(vX2, vX2, vl);                              //x4
235→        vA = __riscv_vfmacc_tu(vA, vB, vX2, vl);                        //A + B * x2
236→        vC = __riscv_vfmacc_tu(vC, vD, vX2, vl);                        //C + D * x2
237→        vA = __riscv_vfmacc_tu(vA, vC, vX4, vl);                        //(A + B * x2) + (C + D * x2) * x4
238→        //--- taylor_poly_f32 end ---
239→
240→        // Reconstruct
241→        vPoly_i32 = __riscv_vreinterpret_v_f32m4_i32m4(vA);
242→        vPoly_i32 = __riscv_vsadd(vPoly_i32, vm_int, vl);
243→        vPoly_f32 = __riscv_vreinterpret_v_i32m4_f32m4(vPoly_i32);
244→        //--- exp_f32 end ---
245→
246→        __riscv_vse32(out_vec2, vPoly_f32, vl);
247→        vSum = __riscv_vfadd_vv_f32m4(vSum, vPoly_f32, vl);             //accumulate sum_f32
248→        in_vec += vl;
249→        out_vec2 += vl;
250→        size2 -= vl;
251→    }
252→    vOut_e0 = __riscv_vfredusum_tu(vOut_e0, vSum, vOut_e0, size);
253→    #ifdef ENA_FAST_ALGO
254→        vl = __riscv_vsetvl_e32m1(1);
255→        vOut_e0 = __riscv_vfrec7(vOut_e0, vl);
256→    #endif
257→    sum = __riscv_vfmv_f(vOut_e0);
258→
259→    //divide the output by sum
260→    vl = __riscv_vsetvlmax_e32m8();
261→    ele_per_loop = vl << 1;
262→    size2 = size;
263→    while (size2 >= ele_per_loop)
264→    {
265→        vfloat32m8_t vOut1, vOut2;
266→        vOut1 = __riscv_vle32_v_f32m8(out_vec, vl);
267→        float32_t* out_vec2 = (float32_t*)out_vec + vl;
268→        vOut2 = __riscv_vle32_v_f32m8(out_vec2, vl);
269→
270→#ifdef ENA_FAST_ALGO
271→        vOut1 = __riscv_vfmul(vOut1, sum, vl);
272→        vOut2 = __riscv_vfmul(vOut2, sum, vl);
273→        __riscv_vse32(out_vec, vOut1, vl);
274→        __riscv_vse32(out_vec2, vOut2, vl);
275→        out_vec += ele_per_loop;
276→#else
277→        vOut1 = __riscv_vfdiv(vOut1, sum, vl);
278→        vOut2 = __riscv_vfdiv(vOut2, sum, vl);
279→        __riscv_vse32(out_vec, vOut1, vl);
280→        __riscv_vse32(out_vec2, vOut2, vl);
281→        out_vec += ele_per_loop;
282→#endif
283→        size2 -= ele_per_loop;
284→    }
285→
286→    while(size2 > 0)
287→    {
288→        vfloat32m8_t vOut;
289→        vl = __riscv_vsetvl_e32m8(size2);
290→        vOut = __riscv_vle32_v_f32m8(out_vec, vl);
291→#ifdef ENA_FAST_ALGO
292→        vOut = __riscv_vfmul(vOut, sum, vl);
293→#else
294→        vOut = __riscv_vfdiv(vOut, sum, vl);
295→#endif
296→        __riscv_vse32(out_vec, vOut, vl);
297→        out_vec += vl;
298→        size2 -= vl;
299→    }
300→#else
301→    //find the maximun
302→    in_vec2 = (float32_t *)in_vec;
303→    NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
304→    NDS_VEC_VLE32_V(NDS_VEC_V0, in_vec2);
305→    in_vec2 += vl;
306→    size2 -= vl;
307→    while(size2 > 0)
308→    {
309→        NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
310→        NDS_VEC_VLE32_V(NDS_VEC_V8, in_vec2);
311→        in_vec2 += vl;
312→        size2 -= vl;
313→        NDS_VEC_VFMAX_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);
314→    }
315→    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note teh avl here
316→    NDS_VEC_VFREDMAX_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V0);
317→    NDS_VEC_VFMV_F_S(max, NDS_VEC_V0);
318→
319→    //calculate the exp and sum
320→    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
321→    NDS_VEC_VAND_VI(NDS_VEC_V28, NDS_VEC_V28, 0);   //init sum
322→    in_vec2 = (float32_t *)in_vec;
323→    out_vec2 = out_vec;
324→    size2 = size;
325→    while(size2 > 0)
326→    {
327→        NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
328→        NDS_VEC_VLE32_V(NDS_VEC_V12, in_vec2);
329→        NDS_VEC_VFSUB_VF(NDS_VEC_V12, NDS_VEC_V12, max);
330→        size2 -= vl;
331→
332→        //--- exp_f32 begin ---
333→        NDS_VEC_VFMAX_VF(NDS_VEC_V12, NDS_VEC_V12, exp_min);
334→        NDS_VEC_VFMIN_VF(NDS_VEC_V12, NDS_VEC_V12, exp_max);
335→        // Perform range reduction [-log(2),log(2)]
336→        NDS_VEC_VFMUL_VF(NDS_VEC_V0, NDS_VEC_V12, inv_ln2);         //x * inv_ln2;
337→        NDS_VEC_VFCVT_RTZ_X_F_V(NDS_VEC_V0, NDS_VEC_V0);            //m (integer type)
338→        NDS_VEC_VFCVT_F_X_V(NDS_VEC_V4, NDS_VEC_V0);                //m (float type)
339→        NDS_VEC_VFNMSUB_VF(NDS_VEC_V4, ln2, NDS_VEC_V12);           //val
340→
341→        //--- taylor_poly_f32 begin ---
342→        NDS_VEC_VFMV_V_F(NDS_VEC_V8, exp_coe0);                     //A = exp_coe0
343→        NDS_VEC_VFMACC_VF(NDS_VEC_V8, exp_coe4, NDS_VEC_V4);        //A = exp_coe0 + x * exp_coe4
344→        NDS_VEC_VFMV_V_F(NDS_VEC_V12, exp_coe2);                    //B = exp_coe2
345→        NDS_VEC_VFMACC_VF(NDS_VEC_V12, exp_coe6, NDS_VEC_V4);       //B = exp_coe2 + x * exp_coe6
346→        NDS_VEC_VFMV_V_F(NDS_VEC_V16, exp_coe1);                    //C = exp_coe1
347→        NDS_VEC_VFMACC_VF(NDS_VEC_V16, exp_coe5, NDS_VEC_V4);       //C = exp_coe1 + x * exp_coe5
348→        NDS_VEC_VFMV_V_F(NDS_VEC_V20, exp_coe3);                    //D = exp_coe3
349→        NDS_VEC_VFMACC_VF(NDS_VEC_V20, exp_coe7, NDS_VEC_V4);       //D = exp_coe3 + x * exp_coe7
350→        NDS_VEC_VFMUL_VV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V4);       //x2
351→        NDS_VEC_VSLL_VX(NDS_VEC_V24, NDS_VEC_V0, 23);               //m2
352→        NDS_VEC_VFMACC_VV(NDS_VEC_V8, NDS_VEC_V12, NDS_VEC_V4);     //A + B * x2
353→        NDS_VEC_VFMACC_VV(NDS_VEC_V16, NDS_VEC_V20, NDS_VEC_V4);    //C + D * x2
354→        NDS_VEC_VFMUL_VV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V4);       //x4
355→        NDS_VEC_VFMACC_VV(NDS_VEC_V8, NDS_VEC_V16, NDS_VEC_V4);     //(A + B * x2) + (C + D * x2) * x4
356→        //--- taylor_poly_f32 end ---
357→
358→        NDS_VEC_VSADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V24);
359→        //--- exp_f32 end ---
360→
361→        NDS_VEC_VFADD_VV(NDS_VEC_V28, NDS_VEC_V28, NDS_VEC_V8);     //accumulate sum_f32
362→        NDS_VEC_VSE32_V(NDS_VEC_V8, out_vec2);
363→        in_vec2 += vl;
364→        out_vec2 += vl;
365→    }
366→    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
367→    NDS_VEC_VAND_VI(NDS_VEC_V20, NDS_VEC_V20, 0);   //for redsum
368→    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
369→    NDS_VEC_VFREDSUM_VS(NDS_VEC_V20, NDS_VEC_V28, NDS_VEC_V20);
370→#ifdef ENA_FAST_ALGO
371→    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
372→    NDS_VEC_VFRECE7_V(NDS_VEC_V20, NDS_VEC_V20);
373→#endif
374→    NDS_VEC_VFMV_F_S(sum, NDS_VEC_V20);
375→
376→    //divide the output by sum
377→    NDS_VEC_VSETVLI(ele_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
378→    ele_per_loop <<= 1;
379→    size2 = size;
380→    NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
381→    while (size2 >= ele_per_loop)
382→    {
383→        float32_t* out_vec2 = (float32_t*)out_vec + vl;
384→        NDS_VEC_VLE32_V(NDS_VEC_V0, out_vec);
385→        NDS_VEC_VLE32_V(NDS_VEC_V8, out_vec2);
386→#ifdef ENA_FAST_ALGO
387→        NDS_VEC_VFMUL_VF(NDS_VEC_V0, NDS_VEC_V0, sum);
388→        NDS_VEC_VFMUL_VF(NDS_VEC_V8, NDS_VEC_V8, sum);
389→#else
390→        NDS_VEC_VFDIV_VF(NDS_VEC_V0, NDS_VEC_V0, sum);
391→        NDS_VEC_VFDIV_VF(NDS_VEC_V8, NDS_VEC_V8, sum);
392→#endif
393→        NDS_VEC_VSE32_V(NDS_VEC_V0, out_vec);
394→        out_vec += ele_per_loop;
395→        NDS_VEC_VSE32_V(NDS_VEC_V8, out_vec2);
396→        size2 -= ele_per_loop;
397→    }
398→    while(size2 > 0)
399→    {
400→        NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
401→        NDS_VEC_VLE32_V(NDS_VEC_V0, out_vec);
402→#ifdef ENA_FAST_ALGO
403→        NDS_VEC_VFMUL_VF(NDS_VEC_V0, NDS_VEC_V0, sum);
404→#else
405→        NDS_VEC_VFDIV_VF(NDS_VEC_V0, NDS_VEC_V0, sum);
406→#endif
407→        NDS_VEC_VSE32_V(NDS_VEC_V0, out_vec);
408→        out_vec += vl;
409→        size2 -= vl;
410→    }
411→#endif
412→#else
413→    float32_t sum = 0;
414→    long i;
415→
416→    float32_t max = in_vec[0];
417→    for(i = 1; i < size; i++)
418→    {
419→        max = (in_vec[i] > max)? in_vec[i] : max;
420→    }
421→
422→    for(i = 0; i < size; i++)
423→    {
424→        out_vec[i] = exp_f32(in_vec[i] - max);
425→        sum += out_vec[i];
426→    }
427→
428→    for(i = 0; i < size; i++)
429→    {
430→        out_vec[i] = out_vec[i] / sum;
431→    }
432→#endif
433→#endif  //ENA_EMPTY_FUN
434→
435→    return 0;
436→}
