 20→ /** @file*/
 21→
 22→#include "internal_nn_math.h"
 23→
 24→//// Basic Operation Functions
 25→
 26→#ifdef ENA_NDS_FPU_HP
 27→int32_t riscv_nn_ew_add_f16(const float16_t * in_vec1,
 28→                            const float16_t * in_vec2,
 29→                            float16_t * out_vec,
 30→                            const uint32_t size)
 31→{
 32→#ifdef ENA_EMPTY_FUN
 33→    //empty body
 34→#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU) && defined(ENA_VEC_INTRINSIC)
 35→    long vl;
 36→    long avl = size;
 37→    vl = __riscv_vsetvl_e16m8(avl);
 38→
 39→    float16_t *a1 = (float16_t*)in_vec1;
 40→    float16_t *a2 = (float16_t*)in_vec1 + vl;
 41→    float16_t *b1 = (float16_t*)in_vec2;
 42→    float16_t *b2 = (float16_t*)in_vec2 + vl;;
 43→    float16_t *c1 = out_vec;
 44→    float16_t *c2 = out_vec + vl;
 45→    long vl_idx = vl << 1;
 46→    while (avl >= vl_idx)
 47→    {
 48→        vfloat16m8_t vA1_f16 = __riscv_vle16_v_f16m8(a1, vl);
 49→        vfloat16m8_t vB1_f16 = __riscv_vle16_v_f16m8(b1, vl);
 50→        vfloat16m8_t vA2_f16 = __riscv_vle16_v_f16m8(a2, vl);
 51→        vfloat16m8_t vB2_f16 = __riscv_vle16_v_f16m8(b2, vl);
 52→        vfloat16m8_t vOut1_f16 = __riscv_vfadd(vA1_f16, vB1_f16, vl);
 53→        vfloat16m8_t vOut2_f16 = __riscv_vfadd(vA2_f16, vB2_f16, vl);
 54→        __riscv_vse16(c1, vOut1_f16, vl);
 55→        __riscv_vse16(c2, vOut2_f16, vl);
 56→        a1 += vl_idx;
 57→        a2 += vl_idx;
 58→        b1 += vl_idx;
 59→        b2 += vl_idx;
 60→        c1 += vl_idx;
 61→        c2 += vl_idx;
 62→        avl -= vl_idx;
 63→    }
 64→    while (avl > 0)
 65→    {
 66→        vl = __riscv_vsetvl_e16m8(avl);
 67→        vfloat16m8_t vA1_f16 = __riscv_vle16_v_f16m8(a1, vl);
 68→        vfloat16m8_t vB1_f16 = __riscv_vle16_v_f16m8(b1, vl);
 69→        vfloat16m8_t vOut1_f16 = __riscv_vfadd(vA1_f16, vB1_f16, vl);
 70→        __riscv_vse16(c1, vOut1_f16, vl);
 71→        a1 += vl;
 72→        b1 += vl;
 73→        c1 += vl;
 74→        avl -= vl;
 75→    }
 76→#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU)
 77→#if 0   //no unrolling version
 78→    uint32_t loop = size;
 79→    uint32_t vl;
 80→    while (loop > 0)
 81→    {
 82→        NDS_VEC_VSETVLI(vl, loop, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
 83→        NDS_VEC_VLH_V(NDS_VEC_V0, in_vec1);
 84→        NDS_VEC_VLH_V(NDS_VEC_V8, in_vec2);
 85→        NDS_VEC_VFADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);
 86→        NDS_VEC_VSH_V(NDS_VEC_V0, out_vec);
 87→        loop -= vl;
 88→        in_vec1 += vl;
 89→        in_vec2 += vl;
 90→        out_vec += vl;
 91→    }
 92→#else
 93→    long vl;
 94→    long avl = size;
 95→    NDS_VEC_VSETVLI(vl, avl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
 96→
 97→    float16_t *a1 = (float16_t*)in_vec1;
 98→    float16_t *a2 = (float16_t*)in_vec1 + vl;
 99→    float16_t *b1 = (float16_t*)in_vec2;
100→    float16_t *b2 = (float16_t*)in_vec2 + vl;;
101→    float16_t *c1 = out_vec;
102→    float16_t *c2 = out_vec + vl;
103→    long vl_idx = vl << 1;
104→
105→    while (avl >= vl_idx)
106→    {
107→        NDS_VEC_VLH_V(NDS_VEC_V0, a1);
108→        NDS_VEC_VLH_V(NDS_VEC_V16, b1);
109→        NDS_VEC_VLH_V(NDS_VEC_V8, a2);
110→        NDS_VEC_VLH_V(NDS_VEC_V24, b2);
111→        NDS_VEC_VFADD_VV(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V0);
112→        NDS_VEC_VFADD_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V8);
113→        NDS_VEC_VSH_V(NDS_VEC_V16, c1);
114→        NDS_VEC_VSH_V(NDS_VEC_V24, c2);
115→        a1 += vl_idx;
116→        a2 += vl_idx;
117→        b1 += vl_idx;
118→        b2 += vl_idx;
119→        c1 += vl_idx;
120→        c2 += vl_idx;
121→        avl -= vl_idx;
122→    }
123→
124→    while (avl > 0)
125→    {
126→        NDS_VEC_VSETVLI(vl, avl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
127→        NDS_VEC_VLH_V(NDS_VEC_V0, a1);
128→        NDS_VEC_VLH_V(NDS_VEC_V16, b1);
129→        NDS_VEC_VFADD_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V0);
130→        NDS_VEC_VSH_V(NDS_VEC_V0, c1);
131→        a1 += vl;
132→        b1 += vl;
133→        c1 += vl;
134→        avl -= vl;
135→    }
136→#endif
137→#else
138→    uint32_t i;
139→    for (i = 0; i < size; i++)
140→    {
141→        out_vec[i] = in_vec1[i] + in_vec2[i];
142→    }
143→#endif  // ENA_VEC_ISA
144→    return 0;
145→}
146→#endif  //ENA_NDS_FPU_HP
