 35→#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU)
 36→    long vl, avl;
 37→
 38→    if (xywh)
 39→    {
 40→        for (int b = 0; b < bs; b++)
 41→        {
 42→            // Move batch-level offsets out of the inner loop
 43→            int b_offset_4 = b * 4 * n_points;
 44→
 45→            // Channel offsets
 46→            const float32_t *dist_l = &pred_dist[b_offset_4];
 47→            const float32_t *dist_t = &pred_dist[b_offset_4 + n_points];
 48→            const float32_t *dist_r = &pred_dist[b_offset_4 + 2 * n_points];
 49→            const float32_t *dist_b = &pred_dist[b_offset_4 + 3 * n_points];
 50→
 51→            float32_t *out_0 = &output[b_offset_4];
 52→            float32_t *out_1 = &output[b_offset_4 + n_points];
 53→            float32_t *out_2 = &output[b_offset_4 + 2 * n_points];
 54→            float32_t *out_3 = &output[b_offset_4 + 3 * n_points];
 55→
 56→            const float32_t *anc_x = &anchor_points[0];
 57→            const float32_t *anc_y = &anchor_points[n_points];
 58→
 59→            avl = n_points;
 60→            while(avl > 0)
 61→            {
 62→                NDS_VEC_VSETVLI(vl, avl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
 63→                NDS_VEC_VLE32_V(NDS_VEC_V0, anc_x); // anc_x
 64→                NDS_VEC_VLE32_V(NDS_VEC_V4, anc_y); // anc_y
 65→
 66→                NDS_VEC_VLE32_V(NDS_VEC_V8, dist_l); // dist_l
 67→                NDS_VEC_VLE32_V(NDS_VEC_V12, dist_t); // dist_t
 68→                NDS_VEC_VLE32_V(NDS_VEC_V16, dist_r); // dist_r
 69→                NDS_VEC_VLE32_V(NDS_VEC_V20, dist_b); // dist_b
 70→
 71→                NDS_VEC_VFSUB_VV(NDS_VEC_V24, NDS_VEC_V0, NDS_VEC_V8); // x1
 72→                NDS_VEC_VFSUB_VV(NDS_VEC_V28, NDS_VEC_V4, NDS_VEC_V12); // y1
 73→                NDS_VEC_VFADD_VV(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V16); // x2
 74→                NDS_VEC_VFADD_VV(NDS_VEC_V12, NDS_VEC_V4, NDS_VEC_V20); // y2
 75→
 76→                NDS_VEC_VFADD_VV(NDS_VEC_V0, NDS_VEC_V24, NDS_VEC_V8); // x1 + x2
 77→                NDS_VEC_VFMUL_VF(NDS_VEC_V0, NDS_VEC_V0, 0.5f); // cx
 78→
 79→                NDS_VEC_VFADD_VV(NDS_VEC_V4, NDS_VEC_V28, NDS_VEC_V12); // y1 + y2
 80→                NDS_VEC_VFMUL_VF(NDS_VEC_V4, NDS_VEC_V4, 0.5f); // cy
 81→
 82→                NDS_VEC_VFSUB_VV(NDS_VEC_V16, NDS_VEC_V8, NDS_VEC_V24); // w
 83→                NDS_VEC_VFSUB_VV(NDS_VEC_V20, NDS_VEC_V12, NDS_VEC_V28); // h
 84→
 85→                NDS_VEC_VSE32_V(NDS_VEC_V0, out_0);
 86→                NDS_VEC_VSE32_V(NDS_VEC_V4, out_1);
 87→                NDS_VEC_VSE32_V(NDS_VEC_V16, out_2);
 88→                NDS_VEC_VSE32_V(NDS_VEC_V20, out_3);
 89→                anc_x += vl;
 90→                anc_y += vl;
 91→                dist_l += vl;
 92→                dist_t += vl;
 93→                dist_r += vl;
 94→                dist_b += vl;
 95→                out_0 += vl;
 96→                out_1 += vl;
 97→                out_2 += vl;
 98→                out_3 += vl;
 99→                avl -= vl;
100→            }
101→        }
102→    }
103→    else
104→    {
105→        for (int b = 0; b < bs; b++)
106→        {
107→            // Move batch-level offsets out of the inner loop
108→            int b_offset_4 = b * 4 * n_points;
109→
110→            // Channel offsets
111→            const float32_t *dist_l = &pred_dist[b_offset_4];
112→            const float32_t *dist_t = &pred_dist[b_offset_4 + n_points];
113→            const float32_t *dist_r = &pred_dist[b_offset_4 + 2 * n_points];
114→            const float32_t *dist_b = &pred_dist[b_offset_4 + 3 * n_points];
115→
116→            float32_t *out_0 = &output[b_offset_4];
117→            float32_t *out_1 = &output[b_offset_4 + n_points];
118→            float32_t *out_2 = &output[b_offset_4 + 2 * n_points];
119→            float32_t *out_3 = &output[b_offset_4 + 3 * n_points];
120→
121→            const float32_t *anc_x = &anchor_points[0];
122→            const float32_t *anc_y = &anchor_points[n_points];
123→
124→            avl = n_points;
125→            while(avl > 0)
126→            {
127→                NDS_VEC_VSETVLI(vl, avl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
128→                NDS_VEC_VLE32_V(NDS_VEC_V0, anc_x); // anc_x
129→                NDS_VEC_VLE32_V(NDS_VEC_V4, anc_y); // anc_y
130→
131→                NDS_VEC_VLE32_V(NDS_VEC_V8, dist_l); // dist_l
132→                NDS_VEC_VLE32_V(NDS_VEC_V12, dist_t); // dist_t
133→                NDS_VEC_VLE32_V(NDS_VEC_V16, dist_r); // dist_r
134→                NDS_VEC_VLE32_V(NDS_VEC_V20, dist_b); // dist_b
135→
136→                NDS_VEC_VFSUB_VV(NDS_VEC_V24, NDS_VEC_V0, NDS_VEC_V8); // x1
137→                NDS_VEC_VFSUB_VV(NDS_VEC_V28, NDS_VEC_V4, NDS_VEC_V12); // y1
138→                NDS_VEC_VFADD_VV(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V16); // x2
139→                NDS_VEC_VFADD_VV(NDS_VEC_V12, NDS_VEC_V4, NDS_VEC_V20); // y2
